// Handler creates http.Handler with routing matching OpenAPI spec.
func Handler(si ServerInterface) http.Handler {
	return HandlerWithOptions(si, StdHTTPServerOptions{})
}

// ServeMux is an abstraction of [http.ServeMux].
type ServeMux interface {
	HandleFunc(pattern string, handler func(http.ResponseWriter, *http.Request))
	http.Handler
}

type StdHTTPServerOptions struct {
	BaseURL          string
	BaseRouter       ServeMux
	Middlewares      []MiddlewareFunc
	ErrorHandlerFunc func(w http.ResponseWriter, r *http.Request, err error)
}

// HandlerFromMux creates http.Handler with routing matching OpenAPI spec based on the provided mux.
func HandlerFromMux(si ServerInterface, m ServeMux) http.Handler {
	return HandlerWithOptions(si, StdHTTPServerOptions{
		BaseRouter: m,
	})
}

func HandlerFromMuxWithBaseURL(si ServerInterface, m ServeMux, baseURL string) http.Handler {
	return HandlerWithOptions(si, StdHTTPServerOptions{
		BaseURL:    baseURL,
		BaseRouter: m,
	})
}

// HandlerWithOptions creates http.Handler with additional options
func HandlerWithOptions(si ServerInterface, options StdHTTPServerOptions) http.Handler {
	m := options.BaseRouter

	if m == nil {
		m = http.NewServeMux()
	}
	if options.ErrorHandlerFunc == nil {
		options.ErrorHandlerFunc = func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusBadRequest)
		}
	}

	wrapper := ServerInterfaceWrapper{
		Handler:            si,
		HandlerMiddlewares: options.Middlewares,
		ErrorHandlerFunc:   options.ErrorHandlerFunc,
	}

	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/api/org/admin/bearers", wrapper.OrgListBearers)
	m.HandleFunc(http.MethodPost+" "+options.BaseURL+"/api/org/admin/revoke", wrapper.OrgRevokeBearer)
	m.HandleFunc(http.MethodPost+" "+options.BaseURL+"/api/org/admin/team-role", wrapper.OrgSetTeamRole)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/api/org/audit", wrapper.OrgAudit)
	m.HandleFunc(http.MethodPost+" "+options.BaseURL+"/api/org/audit/log-drill-down", wrapper.OrgLogDrillDown)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/api/org/budgets", wrapper.OrgBudgetList)
	m.HandleFunc(http.MethodPost+" "+options.BaseURL+"/api/org/budgets", wrapper.OrgBudgetCreate)
	m.HandleFunc(http.MethodDelete+" "+options.BaseURL+"/api/org/budgets/{id}", wrapper.OrgBudgetDelete)
	m.HandleFunc(http.MethodPut+" "+options.BaseURL+"/api/org/budgets/{id}", wrapper.OrgBudgetUpdate)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/api/org/overview", wrapper.OrgOverview)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/api/org/projects", wrapper.OrgProjects)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/api/org/projects/{id}", wrapper.OrgProjectDetail)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/api/org/teams", wrapper.OrgTeams)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/api/org/teams/{id}", wrapper.OrgTeamDetail)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/api/org/teams/{id}/developers", wrapper.OrgTeamDevelopers)

	return m
}
